// src/bundlers/shared/cache.ts
async function processCachedTask({
  cache,
  cacheKey,
  hashKey = cacheKey,
  rawSource,
  readCache,
  applyResult,
  transform,
  onCacheHit
}) {
  let cacheHit = false;
  const result = await cache.process({
    key: cacheKey,
    hashKey,
    rawSource,
    resolveCache: readCache,
    async onCacheHit(value) {
      cacheHit = true;
      await applyResult(value);
      onCacheHit?.();
    },
    transform
  });
  if (!cacheHit) {
    await applyResult(result);
  }
}

export {
  processCachedTask
};
